class Solution:
    def kthFactor(self, n, k):
        small = []
        large = []
        i = 1
        while i * i <= n:
            if n % i == 0:
                small.append(i)
                other = n // i
                if other != i:
                    large.append(other)
            i += 1
        factors = small + large[::-1]
        if k <= len(factors):
            return factors[k - 1]
        return -1

